#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, X; scanf("%lld %lld", &N, &X);
        long long total = N * X;
        if(total >= 10000 && total <= 99999) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

